import jsPDF from "jspdf";

// ✅ PASTE YOUR BASE64 HERE
const logo = "data:image/png;base64,";

export const generatePDF = (invoice, openPreview = false) => {
  const doc = new jsPDF();

  // 🔥 LOGO (NO LOADING ISSUE)
  doc.addImage(logo, "PNG", 10, 8, 40, 20);

  // COMPANY
  doc.setFont("helvetica", "bold");
  doc.setFontSize(16);
  doc.text("BizSaathi Pvt Ltd", 200, 15, { align: "right" });

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("Smart Inventory & GST Billing", 200, 20, { align: "right" });
  doc.text("GSTIN: 22ABCDE1234F1Z5", 200, 25, { align: "right" });

  // TITLE
  doc.setFontSize(18);
  doc.text("TAX INVOICE", 105, 40, { align: "center" });

  // INFO
  doc.setFontSize(11);
  doc.text(`Invoice No: ${invoice.invoiceNumber}`, 10, 55);
  doc.text(
    `Date: ${new Date(invoice.createdAt || Date.now()).toLocaleDateString()}`,
    10,
    62
  );

  doc.text(`Customer: ${invoice.customerName || "-"}`, 120, 55);
  doc.text(`Phone: ${invoice.customerPhone || "-"}`, 120, 62);

  // TABLE
  let y = 75;

  doc.setFillColor(230, 230, 230);
  doc.rect(10, y, 190, 10, "F");

  doc.setFont("helvetica", "bold");
  doc.text("Item", 15, y + 7);
  doc.text("Qty", 90, y + 7);
  doc.text("Price", 120, y + 7);
  doc.text("Total", 160, y + 7);

  y += 15;

  doc.setFont("helvetica", "normal");

  invoice.items.forEach((item) => {
    doc.text(item.name, 15, y);
    doc.text(String(item.qty), 90, y);
    doc.text(`₹${Number(item.price).toFixed(2)}`, 120, y);
    doc.text(`₹${Number(item.total).toFixed(2)}`, 160, y);
    y += 10;
  });

  doc.line(10, y, 200, y);
  y += 10;

  // TOTAL
  doc.rect(110, y, 90, 35);

  doc.text(`Subtotal: ₹${Number(invoice.subtotal).toFixed(2)}`, 115, y + 10);
  doc.text(`CGST: ₹${Number(invoice.cgst).toFixed(2)}`, 115, y + 18);
  doc.text(`SGST: ₹${Number(invoice.sgst).toFixed(2)}`, 115, y + 26);

  doc.setFont("helvetica", "bold");
  doc.setFontSize(13);
  doc.text(`Total: ₹${Number(invoice.total).toFixed(2)}`, 115, y + 34);

  // FOOTER
  doc.setFontSize(10);
  doc.text("Thank you for your business!", 10, 280);

  // ✅ FINAL FIX (WORKS ALWAYS)
  if (openPreview) {
    window.open(doc.output("bloburl"), "_blank");
  } else {
    doc.save(`Invoice-${invoice.invoiceNumber}.pdf`);
  }
};